import { useLocation, useNavigate } from 'react-router-dom';
import { LayoutDashboard, Package, Warehouse, History, ArrowRightLeft, LogOut, User } from 'lucide-react';
import { useAuth } from '../hooks/useAuth';

const NAV = [
  { label: 'Dashboard',    path: '/',           icon: <LayoutDashboard size={16} /> },
  { label: 'Stocks',       path: '/stocks',      icon: <Warehouse size={16} />      },
  { label: 'Produits',     path: '/produits',    icon: <Package size={16} />        },
  { label: 'Mouvements',   path: '/mouvements',  icon: <History size={16} />        },
];

export default function Sidebar() {
  const { pathname } = useLocation();
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <h1>ERP Stock</h1>
        <span>Gestion des stocks</span>
      </div>

      <nav className="sidebar-nav">
        <div className="nav-section-label">Navigation</div>
        {NAV.map(({ label, path, icon }) => (
          <button
            key={path}
            className={`nav-item ${pathname === path ? 'active' : ''}`}
            onClick={() => navigate(path)}
          >
            {icon}
            <span>{label}</span>
          </button>
        ))}
      </nav>

      <div className="sidebar-footer">
        <button
          className="nav-item"
          style={{ width: '100%', color: 'var(--danger)' }}
          onClick={() => window.location.reload()}
        >
          <LogOut size={16} />
          <span>Déconnexion</span>
        </button>
        <div style={{ marginTop: 8, fontSize: 11, color: 'var(--text-muted)', paddingLeft: 4 }}>
          Utilisateur local
        </div>
      </div>
    </aside>
  );
}
